        'maintenanceMode': maintenanceMode,
        'cacheExpiryMinutes': cacheExpiryMinutes,
        'featureFlags': featureFlags,
        'lastFetched': lastFetched?.toIso8601String(),
      };

  factory AppConfig.fromJson(Map<String, dynamic> json) => AppConfig(
        apiBaseUrl: json['apiBaseUrl'] ?? '',
        appVersion: json['appVersion'] ?? '',
        maintenanceMode: json['maintenanceMode'] ?? false,
        cacheExpiryMinutes: json['cacheExpiryMinutes'] ?? 60,
        featureFlags: Map<String, bool>.from(json['featureFlags'] ?? {}),
        lastFetched: json['lastFetched'] != null
            ? DateTime.parse(json['lastFetched'])
            : null,
      );

  factory AppConfig.defaultConfig() => AppConfig(
        apiBaseUrl: 'https://api.example.com',
        appVersion: '1.0.0',
        maintenanceMode: false,
        cacheExpiryMinutes: 60,
        featureFlags: {
          'darkMode': true,
          'notifications': true,
          'analytics': true,
        },
      );
}

class CachedItem<T> {
  final T data;
  final DateTime cachedAt;
  final Duration expiry;

  CachedItem({
    required this.data,
    required this.cachedAt,
    required this.expiry,
  });

  bool get isExpired => DateTime.now().isAfter(cachedAt.add(expiry));
}

