// ==================== Local Storage Manager ====================

class LocalStorageManager {
  static LocalStorageManager? _instance;
  static SharedPreferences? _prefs;

  // In-memory cache for frequently accessed data
  final Map<String, CachedItem<dynamic>> _memoryCache = {};

  LocalStorageManager._();

  static Future<LocalStorageManager> getInstance() async {
    _instance ??= LocalStorageManager._();
    _prefs ??= await SharedPreferences.getInstance();
    return _instance!;
  }

  SharedPreferences get prefs {
    if (_prefs == null) {
      throw Exception(
          'LocalStorageManager not initialized. Call getInstance() first.');
    }
    return _prefs!;
  }

  // ==================== Auth Tokens ====================

  Future<bool> saveAuthTokens(AuthTokens tokens) async {
    final jsonStr = jsonEncode(tokens.toJson());
    _memoryCache[StorageKeys.authTokens] = CachedItem(
      data: tokens,
      cachedAt: DateTime.now(),
      expiry: const Duration(hours: 1),
    );
    return await prefs.setString(StorageKeys.authTokens, jsonStr);
  }

  AuthTokens? getAuthTokens() {
    // Check memory cache first
    final cached = _memoryCache[StorageKeys.authTokens];
    if (cached != null && !cached.isExpired) {
      return cached.data as AuthTokens;
    }

    final jsonStr = prefs.getString(StorageKeys.authTokens);
    if (jsonStr == null) return null;

    try {
      final tokens = AuthTokens.fromJson(jsonDecode(jsonStr));
      _memoryCache[StorageKeys.authTokens] = CachedItem(
        data: tokens,
        cachedAt: DateTime.now(),
        expiry: const Duration(hours: 1),
      );
      return tokens;
    } catch (e) {
      debugPrint('Error parsing auth tokens: $e');
      return null;
    }
  }

  String? getAccessToken() => getAuthTokens()?.accessToken;

  String? getRefreshToken() => getAuthTokens()?.refreshToken;

  bool get isAuthenticated {
    final tokens = getAuthTokens();
    return tokens != null && !tokens.isExpired;
  }

  bool get needsTokenRefresh {
    final tokens = getAuthTokens();
    return tokens != null && tokens.isAboutToExpire;
  }

  Future<bool> clearAuthTokens() async {
    _memoryCache.remove(StorageKeys.authTokens);
    return await prefs.remove(StorageKeys.authTokens);
  }

  // ==================== User Profile ====================

  Future<bool> saveUserProfile(UserProfile profile) async {
    final jsonStr = jsonEncode(profile.toJson());
    _memoryCache[StorageKeys.userProfile] = CachedItem(
      data: profile,
      cachedAt: DateTime.now(),
      expiry: const Duration(hours: 24),
    );
    return await prefs.setString(StorageKeys.userProfile, jsonStr);
  }

  UserProfile? getUserProfile() {
    final cached = _memoryCache[StorageKeys.userProfile];
    if (cached != null && !cached.isExpired) {
      return cached.data as UserProfile;
    }

    final jsonStr = prefs.getString(StorageKeys.userProfile);
    if (jsonStr == null) return null;

    try {
      final profile = UserProfile.fromJson(jsonDecode(jsonStr));
      _memoryCache[StorageKeys.userProfile] = CachedItem(
        data: profile,
        cachedAt: DateTime.now(),
        expiry: const Duration(hours: 24),
      );
      return profile;
    } catch (e) {
      debugPrint('Error parsing user profile: $e');
      return null;
    }
  }

  Future<bool> clearUserProfile() async {
    _memoryCache.remove(StorageKeys.userProfile);
    return await prefs.remove(StorageKeys.userProfile);
  }

  // ==================== App Config ====================

  Future<bool> saveAppConfig(AppConfig config) async {
    final jsonStr = jsonEncode(config.toJson());
    _memoryCache[StorageKeys.appConfig] = CachedItem(
      data: config,
      cachedAt: DateTime.now(),
      expiry: Duration(minutes: config.cacheExpiryMinutes),
    );
    return await prefs.setString(StorageKeys.appConfig, jsonStr);
  }

  AppConfig getAppConfig() {
    final cached = _memoryCache[StorageKeys.appConfig];
    if (cached != null && !cached.isExpired) {
      return cached.data as AppConfig;
    }

    final jsonStr = prefs.getString(StorageKeys.appConfig);
    if (jsonStr == null) return AppConfig.defaultConfig();

    try {
      final config = AppConfig.fromJson(jsonDecode(jsonStr));
      _memoryCache[StorageKeys.appConfig] = CachedItem(
        data: config,
        cachedAt: DateTime.now(),
        expiry: Duration(minutes: config.cacheExpiryMinutes),
      );
      return config;
    } catch (e) {
      debugPrint('Error parsing app config: $e');
      return AppConfig.defaultConfig();
    }
  }

  bool isFeatureEnabled(String featureName) {
    final config = getAppConfig();
    return config.featureFlags[featureName] ?? false;
  }

  // ==================== User Preferences ====================

  Future<bool> setThemeMode(ThemeMode mode) async {
    return await prefs.setString(StorageKeys.themeMode, mode.name);
  }

  ThemeMode getThemeMode() {
    final modeStr = prefs.getString(StorageKeys.themeMode);
    switch (modeStr) {
      case 'light':
        return ThemeMode.light;
      case 'dark':
        return ThemeMode.dark;
      default:
        return ThemeMode.system;
    }
  }

  Future<bool> setLocale(String languageCode) async {
    return await prefs.setString(StorageKeys.locale, languageCode);
  }

  String getLocale() {
    return prefs.getString(StorageKeys.locale) ?? 'en';
  }

  Future<bool> setOnboardingCompleted(bool completed) async {
    return await prefs.setBool(StorageKeys.onboardingCompleted, completed);
  }

  bool get isOnboardingCompleted {
    return prefs.getBool(StorageKeys.onboardingCompleted) ?? false;
  }

  Future<bool> setNotificationsEnabled(bool enabled) async {
    return await prefs.setBool(StorageKeys.notificationsEnabled, enabled);
  }

  bool get isNotificationsEnabled {
    return prefs.getBool(StorageKeys.notificationsEnabled) ?? true;
  }

  Future<bool> setFontSize(double size) async {
    return await prefs.setDouble(StorageKeys.fontSize, size);
  }

  double get fontSize {
    return prefs.getDouble(StorageKeys.fontSize) ?? 14.0;
  }

  Future<bool> setBiometricEnabled(bool enabled) async {
    return await prefs.setBool(StorageKeys.biometricEnabled, enabled);
  }

  bool get isBiometricEnabled {
    return prefs.getBool(StorageKeys.biometricEnabled) ?? false;
  }

  Future<bool> setAutoLoginEnabled(bool enabled) async {
    return await prefs.setBool(StorageKeys.autoLoginEnabled, enabled);
  }

  bool get isAutoLoginEnabled {
    return prefs.getBool(StorageKeys.autoLoginEnabled) ?? false;
  }

  Future<bool> setDataUsageWifiOnly(bool wifiOnly) async {
    return await prefs.setBool(StorageKeys.dataUsageWifiOnly, wifiOnly);
  }

  bool get isDataUsageWifiOnly {
    return prefs.getBool(StorageKeys.dataUsageWifiOnly) ?? false;
  }

  // ==================== Cached Content ====================

  Future<bool> cacheData(String key, dynamic data,
      {Duration expiry = const Duration(hours: 1)}) async {
    final cacheKey = '${StorageKeys.cachedPrefix}$key';
    final cacheEntry = {
      'data': data,
      'cachedAt': DateTime.now().toIso8601String(),
      'expiryMinutes': expiry.inMinutes,
    };

    _memoryCache[cacheKey] = CachedItem(
      data: data,
      cachedAt: DateTime.now(),
      expiry: expiry,
    );

    return await prefs.setString(cacheKey, jsonEncode(cacheEntry));
  }

  T? getCachedData<T>(String key) {
    final cacheKey = '${StorageKeys.cachedPrefix}$key';

    // Check memory cache
    final memoryCached = _memoryCache[cacheKey];
    if (memoryCached != null && !memoryCached.isExpired) {
      return memoryCached.data as T?;
    }

    final jsonStr = prefs.getString(cacheKey);
    if (jsonStr == null) return null;

    try {
      final cacheEntry = jsonDecode(jsonStr);
      final cachedAt = DateTime.parse(cacheEntry['cachedAt']);
      final expiryMinutes = cacheEntry['expiryMinutes'] as int;
      final expiry = Duration(minutes: expiryMinutes);

      if (DateTime.now().isAfter(cachedAt.add(expiry))) {
        // Cache expired, remove it
        prefs.remove(cacheKey);
        _memoryCache.remove(cacheKey);
        return null;
      }

      final data = cacheEntry['data'];
      _memoryCache[cacheKey] = CachedItem(
        data: data,
        cachedAt: cachedAt,
        expiry: expiry,
      );

      return data as T?;
    } catch (e) {
      debugPrint('Error reading cached data for key $key: $e');
      return null;
    }
  }

  Future<bool> removeCachedData(String key) async {
    final cacheKey = '${StorageKeys.cachedPrefix}$key';
    _memoryCache.remove(cacheKey);
    return await prefs.remove(cacheKey);
  }

  bool isCacheValid(String key) {
    return getCachedData(key) != null;
  }

  // ==================== Offline Data ====================

  Future<bool> saveOfflineData(String key, dynamic data) async {
    final offlineKey = '${StorageKeys.offlineDataPrefix}$key';
    final entry = {
      'data': data,
      'savedAt': DateTime.now().toIso8601String(),
    };
    return await prefs.setString(offlineKey, jsonEncode(entry));
  }

  T? getOfflineData<T>(String key) {
    final offlineKey = '${StorageKeys.offlineDataPrefix}$key';
    final jsonStr = prefs.getString(offlineKey);
    if (jsonStr == null) return null;

    try {
      final entry = jsonDecode(jsonStr);
      return entry['data'] as T?;
    } catch (e) {
      debugPrint('Error reading offline data for key $key: $e');
      return null;
    }
  }

  DateTime? getOfflineDataTimestamp(String key) {
    final offlineKey = '${StorageKeys.offlineDataPrefix}$key';
    final jsonStr = prefs.getString(offlineKey);
    if (jsonStr == null) return null;

    try {
      final entry = jsonDecode(jsonStr);
      return DateTime.parse(entry['savedAt']);
    } catch (e) {
      return null;
    }
  }

  Future<bool> removeOfflineData(String key) async {
    final offlineKey = '${StorageKeys.offlineDataPrefix}$key';
    return await prefs.remove(offlineKey);
  }

  // ==================== Search History ====================

  Future<bool> addSearchQuery(String query) async {
    final history = getSearchHistory();
    history.remove(query); // Remove duplicate
    history.insert(0, query); // Add to beginning

    // Keep only last 20 searches
    if (history.length > 20) {
      history.removeRange(20, history.length);
    }

    return await prefs.setStringList(StorageKeys.searchHistory, history);
  }

  List<String> getSearchHistory() {
    return prefs.getStringList(StorageKeys.searchHistory) ?? [];
  }

  Future<bool> clearSearchHistory() async {
    return await prefs.remove(StorageKeys.searchHistory);
  }

  Future<bool> removeSearchQuery(String query) async {
    final history = getSearchHistory();
    history.remove(query);
    return await prefs.setStringList(StorageKeys.searchHistory, history);
  }

  // ==================== Recent Items ====================

  Future<bool> addRecentItem(Map<String, dynamic> item) async {
    final items = getRecentItems();
    // Remove existing item with same id
    items.removeWhere((i) => i['id'] == item['id']);
    items.insert(0, item);

    // Keep only last 50 items
    if (items.length > 50) {
      items.removeRange(50, items.length);
    }

    final jsonStr = jsonEncode(items);
    return await prefs.setString(StorageKeys.recentItems, jsonStr);
  }

  List<Map<String, dynamic>> getRecentItems() {
    final jsonStr = prefs.getString(StorageKeys.recentItems);
    if (jsonStr == null) return [];

    try {
      final list = jsonDecode(jsonStr) as List;
      return list.map((e) => Map<String, dynamic>.from(e)).toList();
    } catch (e) {
      debugPrint('Error parsing recent items: $e');
      return [];
    }
  }

  Future<bool> clearRecentItems() async {
    return await prefs.remove(StorageKeys.recentItems);
  }

  // ==================== Sync Management ====================

  Future<bool> setLastSyncTime(DateTime time) async {
    return await prefs.setString(
        StorageKeys.lastSyncTime, time.toIso8601String());
  }

  DateTime? get lastSyncTime {
    final timeStr = prefs.getString(StorageKeys.lastSyncTime);
    if (timeStr == null) return null;
    return DateTime.tryParse(timeStr);
  }

  bool get needsSync {
    final last = lastSyncTime;
    if (last == null) return true;
    return DateTime.now().difference(last) > const Duration(hours: 1);
  }

  // ==================== Bulk Operations ====================

  Future<void> clearAllCache() async {
    final keys = prefs.getKeys();
    for (final key in keys) {
      if (key.startsWith(StorageKeys.cachedPrefix)) {
        await prefs.remove(key);
      }
    }
    _memoryCache.removeWhere(
        (key, _) => key.startsWith(StorageKeys.cachedPrefix));
  }

  Future<void> clearAllOfflineData() async {
    final keys = prefs.getKeys();
    for (final key in keys) {
      if (key.startsWith(StorageKeys.offlineDataPrefix)) {
        await prefs.remove(key);
      }
    }
  }

  Future<void> logout() async {
    await clearAuthTokens();
    await clearUserProfile();
    await clearAllCache();
    await clearSearchHistory();
    await clearRecentItems();
    _memoryCache.clear();
    await prefs.remove(StorageKeys.lastSyncTime);
    // Keep user preferences (theme, locale, etc.)
  }

  Future<void> clearAll() async {
    _memoryCache.clear();
    await prefs.clear();
  }

  // ==================== Storage Info ====================

  Map<String, dynamic> getStorageInfo() {
    final keys = prefs.getKeys();
    int cachedCount = 0;
    int offlineCount = 0;
    int prefsCount = 0;

    for (final key in keys) {
      if (key.startsWith(StorageKeys.cachedPrefix)) {
        cachedCount++;
      } else if (key.startsWith(StorageKeys.offlineDataPrefix)) {
        offlineCount++;
      } else {
        prefsCount++;
      }
    }

    return {
      'totalKeys': keys.length,
      'cachedItems': cachedCount,
      'offlineItems': offlineCount,
      'preferences': prefsCount,
      'memoryCacheItems': _memoryCache.length,
      'isAuthenticated': isAuthenticated,
      'lastSync': lastSyncTime?.toIso8601String(),
    };
  }
}

