    final draft = _storage.getOfflineData<Map>('draft_message');
    final timestamp = _storage.getOfflineDataTimestamp('pending_orders');

    _log('✅ Offline Data Saved & Loaded\n'
        'Pending Orders: ${orders?.length ?? 0}\n'
        'First Order: ${orders?.first['orderId']}\n'
        'Draft To: ${draft?['to']}\n'
        'Saved At: $timestamp');
  }

  Future<void> _demoSearchHistory() async {
    await _storage.addSearchQuery('Flutter widgets');
    await _storage.addSearchQuery('Dart async');
    await _storage.addSearchQuery('SharedPreferences');
    await _storage.addSearchQuery('State management');
    await _storage.addSearchQuery('Flutter widgets'); // Duplicate - moves to top

    final history = _storage.getSearchHistory();
    _log('✅ Search History\n'
        'Items: ${history.length}\n'
        'History: ${history.join(', ')}');
  }

  Future<void> _demoRecentItems() async {
    await _storage.addRecentItem({
      'id': 'product_1',
      'name': 'Wireless Headphones',
      'price': 79.99,
    });
    await _storage.addRecentItem({
      'id': 'product_2',
      'name': 'USB-C Cable',
      'price': 12.99,
    });
    await _storage.addRecentItem({
      'id': 'product_3',
      'name': 'Phone Case',
      'price': 24.99,
    });

    final items = _storage.getRecentItems();
    _log('✅ Recent Items\n'
        'Count: ${items.length}\n'
        'Items: ${items.map((i) => i['name']).join(', ')}');
  }

  Future<void> _showStorageInfo() async {
    final info = _storage.getStorageInfo();
    final buffer = StringBuffer('📊 Storage Info\n');
    info.forEach((key, value) {
      buffer.writeln('  $key: $value');
    });
    _log(buffer.toString());
  }

  Future<void> _demoSync() async {
    await _storage.setLastSyncTime(DateTime.now());
    _log('🔄 Sync Info\n'
        'Last Sync: ${_storage.lastSyncTime}\n'
        'Needs Sync: ${_storage.needsSync}');
  }

  Future<void> _clearCache() async {
    await _storage.clearAllCache();
    _log('🗑️ All cached content cleared');
  }

  Future<void> _logout() async {
    await _storage.logout();
    _log('🚪 Logged out - Auth, profile, cache, history cleared\n'
        'Preferences retained (theme, locale, etc.)');
  }

  Future<void> _clearAll() async {
    await _storage.clearAll();
    _log('💥 All storage cleared completely');
  }

  @override
  Widget build(BuildContext context) {
    if (!_initialized) {
      return const Scaffold(
        body: Center(child: CircularProgressIndicator()),
      );
    }

    return Scaffold(
      appBar: AppBar(
        title: const Text('Local Storage Manager'),
        centerTitle: true,
        elevation: 2,
      ),
      body: Column(
        children: [
          Expanded(
            flex: 2,
            child: SingleChildScrollView(
              padding: const EdgeInsets.all(12),
              child: Wrap(
                spacing: 8,
                runSpacing: 8,
                children: [
                  _buildActionButton(
                      '🔐 Auth Tokens', _demoAuthTokens, Colors.red),
                  _buildActionButton(
                      '👤 User Profile', _demoUserProfile, Colors.blue),
                  _buildActionButton(
                      '⚙️ App Config', _demoAppConfig, Colors.green),
                  _buildActionButton(
                      '🎨 Preferences', _demoPreferences, Colors.purple),
                  _buildActionButton(
                      '💾 Cache Content', _demoCachedContent, Colors.orange),
                  _buildActionButton(
                      '📴 Offline Data', _demoOfflineData, Colors.teal),
                  _buildActionButton(
                      '🔍 Search History', _demoSearchHistory, Colors.indigo),
                  _buildActionButton(
                      '🕐 Recent Items', _demoRecentItems, Colors.brown),
                  _buildActionButton(
                      '🔄 Sync Demo', _demoSync, Colors.cyan),
                  _buildActionButton(
                      '📊 Storage Info', _showStorageInfo, Colors.blueGrey),
                  _buildActionButton(
                      '🗑️ Clear Cache', _clearCache, Colors.amber),
                  _buildActionButton(
                      '🚪 Logout', _logout, Colors.deepOrange),
                  _buildActionButton(
                      '💥 Clear All', _clearAll, Colors.red.shade900),
                ],
              ),
            ),
          ),
          const Divider(height: 1),
          Expanded(
            flex: 3,
            child: Container(
              width: double.infinity,
              color: Theme.of(context).colorScheme.surfaceContainerLowest,
              child: SingleChildScrollView(
                padding: const EdgeInsets.all(12),
                child: SelectableText(
                  _output.isEmpty ? 'Tap a button to test...' : _output,
                  style: TextStyle(
                    fontFamily: 'monospace',
                    fontSize: 13,
                    color: Theme.of(context).colorScheme.onSurface,
                  ),
                ),
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildActionButton(
      String label, VoidCallback onPressed, Color color) {
    return ElevatedButton(
      onPressed: onPressed,
      style: ElevatedButton.styleFrom(
        backgroundColor: color.withOpacity(0.1),
        foregroundColor: color,
        side: BorderSide(color: color.withOpacity(0.3)),
        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 10),
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(8)),
      ),
      child: Text(label, style: const TextStyle(fontSize: 12)),
    );
  }
}